// ❌ BAD - Using RSA to encrypt a large customer report payload
using var rsa = RSA.Create(2048);
// RSA has a size limit (~214 bytes for 2048-bit) - this throws on large data
byte[] encryptedReport = rsa.Encrypt(Encoding.UTF8.GetBytes(largeReportJson), RSAEncryptionPadding.OaepSHA256);

// ✅ GOOD - Use AES for bulk data, RSA only to protect the AES key
using var aes = Aes.Create();
aes.GenerateKey(); aes.GenerateIV();
byte[] encryptedKey = rsa.Encrypt(aes.Key, RSAEncryptionPadding.OaepSHA256);
byte[] encryptedReport = aes.EncryptCbc(Encoding.UTF8.GetBytes(largeReportJson), aes.IV);

// ❌ BAD - Encrypting a password means it can be decrypted and exposed in a breach
string encryptedPassword = Convert.ToBase64String(
    ProtectedData.Protect(Encoding.UTF8.GetBytes(customerPassword), null, DataProtectionScope.LocalMachine));

// ✅ GOOD - Hash with bcrypt so the original password is never recoverable
string hashedPassword = BCrypt.Net.BCrypt.HashPassword(customerPassword, workFactor: 12);
bool isValid = BCrypt.Net.BCrypt.Verify(customerPassword, hashedPassword);

// ❌ BAD - Fast hash with no salt allows rainbow table attacks and instant brute force
string storedHash = Convert.ToHexString(
    SHA256.HashData(Encoding.UTF8.GetBytes(customerPassword)));

// ✅ GOOD - bcrypt with work factor 12 - slow, salted, self-contained
string storedHash = BCrypt.Net.BCrypt.HashPassword(customerPassword, workFactor: 12);
bool loginOk = BCrypt.Net.BCrypt.Verify(submittedPassword, storedHash);

// ❌ BAD - Connection string hardcoded in appsettings.json committed to git
// { "ConnectionStrings": { "OrderDb": "Server=prod;Password=Sup3rS3cr3t!" } }

// ✅ GOOD - Load secrets from Azure Key Vault at startup via Managed Identity
builder.Configuration.AddAzureKeyVault(
    new Uri("https://kv-ordering-prod.vault.azure.net/"),
    new DefaultAzureCredential());
// App reads: builder.Configuration["OrderDb--ConnectionString"]
// Same IConfiguration API - no Key Vault code in business logic

// ❌ BAD - HTTP client without enforcing TLS minimum - data may travel in plaintext
var client = new HttpClient();
var response = await client.GetAsync("http://internal-inventory-api/products");

// ✅ GOOD - Enforce TLS 1.2+ for in-transit protection
var handler = new HttpClientHandler
{
    SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13
};
var client = new HttpClient(handler);
var response = await client.GetAsync("https://internal-inventory-api/products");

// ❌ BAD - Manual tenant filter per query trusts client-supplied value
var orders = await _db.Orders
    .Where(o => o.TenantId == tenantIdFromRequestBody)
    .ToListAsync();

// ✅ GOOD - Global query filter enforced centrally in DbContext
modelBuilder.Entity<Order>()
    .HasQueryFilter(o => o.TenantId == _tenantContext.CurrentTenantId);
// _tenantContext resolves TenantId from the authenticated user's JWT claim
// Every Orders query is automatically scoped - developer cannot forget it

// ❌ BAD - Logging full PII visible in log aggregators and long-term retention
_logger.LogInformation("Order placed by {Email} from {IpAddress}",
    customer.Email, httpContext.Connection.RemoteIpAddress);

// ✅ GOOD - Log only a non-reversible identifier, keep PII out of logs
_logger.LogInformation("Order {OrderId} placed by customer {CustomerId}",
    order.Id, customer.Id);

// ❌ BAD - App connects as db_owner - can drop tables, read all schemas, run xp_cmdshell
// Connection string: "User=app_dbo_admin;Password=xxx" (db_owner role)

// ✅ GOOD - Managed Identity with table-level permissions only
// Connection string uses Active Directory Managed Identity - no password
// SQL Server grant: GRANT SELECT, INSERT, UPDATE ON dbo.Orders TO [app-managed-identity]
// GRANT SELECT ON dbo.Products TO [app-managed-identity] - nothing else
var conn = new SqlConnection("Server=prod-sql.database.windows.net;Authentication=Active Directory Managed Identity");

// ❌ BAD - API key hardcoded in source file and committed - now in git history forever
// appsettings.json: { "Stripe": { "SecretKey": "sk_live_4xRealStripeKey..." } }

// ✅ GOOD - Read from Key Vault at runtime, no secret in any file
builder.Services.Configure<StripeOptions>(options =>
{
    // Value injected from Key Vault via IConfiguration at startup
    options.SecretKey = builder.Configuration["Stripe:SecretKey"];
});
